import React, { useState, useEffect, useRef } from "react";
import { useNavigate } from "react-router-dom";
import Nav from "./Nev";

// ─── Pet breed categories for filter ─────────────────────────
const CATEGORIES = ["All", "Dogs", "Cats", "Birds", "Fish", "Rabbits", "Exotic"];

// ─── Fallback pet images (Unsplash — free) ───────────────────
const FALLBACK_IMGS = [
  "https://images.unsplash.com/photo-1587300003388-59208cc962cb?w=400&q=80",
  "https://images.unsplash.com/photo-1548199973-03cce0bbc87b?w=400&q=80",
  "https://images.unsplash.com/photo-1537151608828-ea2b11777ee8?w=400&q=80",
  "https://images.unsplash.com/photo-1583511655857-d19b40a7a54e?w=400&q=80",
  "https://images.unsplash.com/photo-1601979031925-424e53b6caaa?w=400&q=80",
  "https://images.unsplash.com/photo-1518717758536-85ae29035b6d?w=400&q=80",
];

// ─── Styles ───────────────────────────────────────────────────
const css = `
  @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,700;0,800;1,700&family=Outfit:wght@300;400;500;600;700&display=swap');

  :root {
    --cream: #fdf8f3;
    --brown: #3d2b1f;
    --amber: #c8834a;
    --amber-light: #f0b97a;
    --green: #2d5016;
    --green-mid: #4a7c2f;
    --green-light: #7ab648;
    --white: #ffffff;
    --card-bg: #ffffff;
    --border: rgba(61,43,31,0.1);
    --shadow: 0 4px 32px rgba(61,43,31,0.1);
    --shadow-hover: 0 20px 60px rgba(61,43,31,0.18);
  }

  .pg-root { min-height:100vh; background:var(--cream); font-family:'Outfit',sans-serif; }

  /* ── HERO ── */
  .pg-hero {
    background: linear-gradient(135deg, #1a3a06 0%, #2d5016 40%, #3d6b20 70%, #c8834a 100%);
    padding: 80px 20px 100px;
    text-align: center;
    position: relative;
    overflow: hidden;
  }
  .pg-hero::before {
    content:'';position:absolute;inset:0;
    background: url("data:image/svg+xml,%3Csvg width='60' height='60' viewBox='0 0 60 60' xmlns='http://www.w3.org/2000/svg'%3E%3Cg fill='none' fill-rule='evenodd'%3E%3Cg fill='%23ffffff' fill-opacity='0.03'%3E%3Ccircle cx='30' cy='30' r='4'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");
  }
  .pg-hero-tag {
    display:inline-block; background:rgba(200,131,74,0.25); border:1px solid rgba(200,131,74,0.5);
    color:#f0b97a; font-size:11px; font-weight:600; letter-spacing:4px; text-transform:uppercase;
    padding:6px 18px; border-radius:30px; margin-bottom:20px;
    animation: fadeDown 0.6s ease;
  }
  .pg-hero h1 {
    font-family:'Playfair Display',serif; font-size:clamp(36px,6vw,68px); font-weight:800;
    color:#fff; line-height:1.1; margin:0 0 16px;
    animation: fadeDown 0.7s ease;
  }
  .pg-hero h1 em { font-style:italic; color:#f0b97a; }
  .pg-hero p {
    color:rgba(255,255,255,0.65); font-size:16px; font-weight:300; max-width:480px;
    margin:0 auto 36px; line-height:1.7; animation:fadeDown 0.8s ease;
  }
  .pg-stats {
    display:flex; justify-content:center; gap:40px; flex-wrap:wrap;
    animation:fadeDown 0.9s ease;
  }
  .pg-stat { text-align:center; }
  .pg-stat-num { font-family:'Playfair Display',serif; font-size:28px; font-weight:700; color:#f0b97a; display:block; }
  .pg-stat-label { font-size:11px; color:rgba(255,255,255,0.5); letter-spacing:2px; text-transform:uppercase; }

  /* ── SEARCH + FILTER BAR ── */
  .pg-bar {
    max-width:1100px; margin:-28px auto 0; padding:0 20px;
    position:relative; z-index:10;
  }
  .pg-bar-inner {
    background:#fff; border-radius:20px; padding:20px 24px;
    box-shadow: 0 8px 48px rgba(61,43,31,0.14);
    display:flex; gap:14px; align-items:center; flex-wrap:wrap;
  }
  .pg-search {
    flex:1; min-width:200px; display:flex; align-items:center; gap:10px;
    background:#fdf8f3; border:1.5px solid var(--border); border-radius:12px; padding:11px 16px;
    transition:all 0.2s;
  }
  .pg-search:focus-within { border-color:var(--amber); box-shadow:0 0 0 3px rgba(200,131,74,0.12); }
  .pg-search-icon { color:var(--amber); font-size:16px; flex-shrink:0; }
  .pg-search input {
    border:none; background:transparent; outline:none; font-family:'Outfit',sans-serif;
    font-size:14px; color:var(--brown); width:100%;
  }
  .pg-search input::placeholder { color:#bba898; }
  .pg-sort {
    background:#fdf8f3; border:1.5px solid var(--border); border-radius:12px;
    padding:11px 14px; font-family:'Outfit',sans-serif; font-size:13px; font-weight:500;
    color:var(--brown); cursor:pointer; outline:none; transition:all 0.2s;
  }
  .pg-sort:focus { border-color:var(--amber); }
  .pg-view-btns { display:flex; gap:6px; }
  .pg-view-btn {
    width:40px; height:40px; border-radius:10px; border:1.5px solid var(--border);
    background:transparent; cursor:pointer; font-size:16px; transition:all 0.2s;
    display:flex; align-items:center; justify-content:center;
  }
  .pg-view-btn.active { background:var(--amber); border-color:var(--amber); color:#fff; }

  /* ── CATEGORY CHIPS ── */
  .pg-cats {
    max-width:1100px; margin:20px auto 0; padding:0 20px;
    display:flex; gap:10px; flex-wrap:wrap;
  }
  .pg-cat {
    padding:8px 20px; border-radius:30px; border:1.5px solid var(--border);
    background:#fff; color:#7a6055; font-size:13px; font-weight:500;
    cursor:pointer; transition:all 0.2s; display:flex; align-items:center; gap:6px;
  }
  .pg-cat:hover { border-color:var(--amber); color:var(--amber); transform:translateY(-1px); }
  .pg-cat.active {
    background:linear-gradient(135deg,var(--green),var(--green-mid));
    border-color:transparent; color:#fff;
    box-shadow:0 4px 16px rgba(45,80,22,0.3);
  }
  .pg-count { font-size:10px; background:rgba(255,255,255,0.25); padding:1px 7px; border-radius:10px; }

  /* ── RESULTS INFO ── */
  .pg-info {
    max-width:1100px; margin:24px auto 0; padding:0 20px;
    display:flex; justify-content:space-between; align-items:center;
  }
  .pg-results { font-size:13px; color:#9a857a; }
  .pg-results strong { color:var(--brown); }
  .pg-clear { font-size:12px; color:var(--amber); cursor:pointer; font-weight:600; background:none; border:none; }
  .pg-clear:hover { text-decoration:underline; }

  /* ── GRID ── */
  .pg-grid {
    max-width:1100px; margin:20px auto 0; padding:0 20px 80px;
    display:grid; gap:24px;
    grid-template-columns: repeat(auto-fill, minmax(260px, 1fr));
  }
  .pg-grid.list-view { grid-template-columns:1fr; }

  /* ── CARD ── */
  .pg-card {
    background:var(--card-bg); border-radius:20px; overflow:hidden;
    border:1px solid var(--border); box-shadow:var(--shadow);
    transition:all 0.35s cubic-bezier(0.34,1.26,0.64,1);
    cursor:pointer; position:relative;
    animation: cardIn 0.5s ease both;
  }
  .pg-card:hover {
    transform:translateY(-8px) scale(1.01);
    box-shadow:var(--shadow-hover);
    border-color:rgba(200,131,74,0.3);
  }
  .pg-card.list-view {
    display:grid; grid-template-columns:200px 1fr; border-radius:16px;
  }
  .pg-card.list-view:hover { transform:translateY(-3px) scale(1.005); }

  /* Card Image */
  .pg-img-wrap {
    position:relative; overflow:hidden; aspect-ratio:4/3; background:#f5ede4;
  }
  .pg-card.list-view .pg-img-wrap { aspect-ratio:unset; height:160px; }
  .pg-img {
    width:100%; height:100%; object-fit:cover;
    transition:transform 0.6s cubic-bezier(0.25,0.46,0.45,0.94);
  }
  .pg-card:hover .pg-img { transform:scale(1.08); }
  .pg-img-overlay {
    position:absolute; inset:0;
    background:linear-gradient(to top, rgba(30,20,10,0.6) 0%, transparent 50%);
    opacity:0; transition:opacity 0.3s;
  }
  .pg-card:hover .pg-img-overlay { opacity:1; }

  /* Badges */
  .pg-badge {
    position:absolute; top:12px; left:12px; padding:4px 10px; border-radius:8px;
    font-size:10px; font-weight:700; letter-spacing:1px; text-transform:uppercase;
  }
  .pg-badge.new { background:#10b981; color:#fff; }
  .pg-badge.hot { background:#ef4444; color:#fff; }
  .pg-badge.sale { background:var(--amber); color:#fff; }

  /* Wishlist */
  .pg-wish {
    position:absolute; top:12px; right:12px; width:34px; height:34px;
    border-radius:50%; background:rgba(255,255,255,0.9); border:none; cursor:pointer;
    display:flex; align-items:center; justify-content:center; font-size:16px;
    transition:all 0.2s; backdrop-filter:blur(4px);
    opacity:0; transform:translateY(-4px);
  }
  .pg-card:hover .pg-wish { opacity:1; transform:translateY(0); }
  .pg-wish.liked { opacity:1; background:#fff1f2; }
  .pg-wish:hover { transform:scale(1.15) !important; }

  /* Quick view overlay button */
  .pg-quick {
    position:absolute; bottom:12px; left:50%; transform:translateX(-50%) translateY(8px);
    background:rgba(255,255,255,0.95); border:none; border-radius:10px;
    padding:8px 18px; font-family:'Outfit',sans-serif; font-size:12px; font-weight:600;
    color:var(--brown); cursor:pointer; white-space:nowrap;
    opacity:0; transition:all 0.25s; backdrop-filter:blur(4px);
  }
  .pg-card:hover .pg-quick { opacity:1; transform:translateX(-50%) translateY(0); }

  /* Card Body */
  .pg-body { padding:18px 18px 16px; }
  .pg-card.list-view .pg-body { padding:20px 24px; display:flex; flex-direction:column; justify-content:center; }
  .pg-cat-tag {
    font-size:10px; font-weight:600; letter-spacing:2px; text-transform:uppercase;
    color:var(--green-mid); margin-bottom:6px; display:flex; align-items:center; gap:4px;
  }
  .pg-cat-tag::before { content:''; display:inline-block; width:6px; height:6px; border-radius:50%; background:var(--green-light); }
  .pg-name {
    font-family:'Playfair Display',serif; font-size:18px; font-weight:700; color:var(--brown);
    margin:0 0 6px; line-height:1.3;
  }
  .pg-card.list-view .pg-name { font-size:22px; }
  .pg-desc { font-size:12px; color:#9a857a; line-height:1.6; margin-bottom:12px; }
  .pg-rating { display:flex; align-items:center; gap:4px; margin-bottom:12px; }
  .pg-stars { color:#f0b97a; font-size:12px; letter-spacing:1px; }
  .pg-rating-count { font-size:11px; color:#bba898; }

  /* Price Row */
  .pg-price-row { display:flex; align-items:center; justify-content:space-between; gap:8px; }
  .pg-price {
    font-family:'Playfair Display',serif; font-size:22px; font-weight:700; color:var(--brown);
  }
  .pg-price em { font-style:normal; font-size:14px; color:var(--amber); }
  .pg-price-old { font-size:13px; color:#c4a99a; text-decoration:line-through; margin-left:4px; }
  .pg-add-btn {
    padding:9px 18px; border-radius:12px; border:none;
    background:linear-gradient(135deg,var(--green),var(--green-mid));
    color:#fff; font-family:'Outfit',sans-serif; font-size:12px; font-weight:600;
    cursor:pointer; transition:all 0.2s; white-space:nowrap;
    box-shadow:0 4px 14px rgba(45,80,22,0.3);
  }
  .pg-add-btn:hover { transform:translateY(-2px); box-shadow:0 8px 20px rgba(45,80,22,0.4); }
  .pg-add-btn.added { background:linear-gradient(135deg,#10b981,#059669); }

  /* ── QUICK VIEW MODAL ── */
  .pg-modal-bg {
    position:fixed; inset:0; background:rgba(20,10,5,0.7); z-index:1000;
    display:flex; align-items:center; justify-content:center; padding:20px;
    backdrop-filter:blur(6px); animation:fadeIn 0.2s ease;
  }
  .pg-modal {
    background:#fff; border-radius:24px; max-width:700px; width:100%;
    max-height:90vh; overflow-y:auto; position:relative;
    animation:popIn 0.3s cubic-bezier(0.34,1.56,0.64,1);
    box-shadow:0 32px 80px rgba(0,0,0,0.3);
  }
  .pg-modal-img { width:100%; height:300px; object-fit:cover; border-radius:24px 24px 0 0; }
  .pg-modal-body { padding:28px 32px 32px; }
  .pg-modal-close {
    position:absolute; top:16px; right:16px; width:36px; height:36px;
    border-radius:50%; background:rgba(255,255,255,0.9); border:none;
    font-size:18px; cursor:pointer; display:flex; align-items:center; justify-content:center;
    box-shadow:0 2px 12px rgba(0,0,0,0.15); transition:all 0.2s;
  }
  .pg-modal-close:hover { transform:scale(1.1) rotate(90deg); }
  .pg-modal-name { font-family:'Playfair Display',serif; font-size:28px; color:var(--brown); margin:0 0 8px; }
  .pg-modal-price { font-family:'Playfair Display',serif; font-size:32px; color:var(--amber); margin:0 0 16px; }
  .pg-modal-features { display:grid; grid-template-columns:1fr 1fr; gap:10px; margin-bottom:20px; }
  .pg-modal-feat {
    background:#fdf8f3; border-radius:10px; padding:12px 14px;
    font-size:12px; color:#7a6055;
  }
  .pg-modal-feat strong { display:block; color:var(--brown); font-size:13px; margin-bottom:2px; }
  .pg-modal-actions { display:flex; gap:12px; }
  .pg-modal-cart {
    flex:1; padding:14px; background:linear-gradient(135deg,var(--green),var(--green-mid));
    color:#fff; border:none; border-radius:14px; font-family:'Outfit',sans-serif;
    font-size:15px; font-weight:700; cursor:pointer; transition:all 0.2s;
    box-shadow:0 6px 20px rgba(45,80,22,0.3);
  }
  .pg-modal-cart:hover { transform:translateY(-2px); box-shadow:0 10px 28px rgba(45,80,22,0.4); }
  .pg-modal-wish2 {
    padding:14px 20px; border-radius:14px; border:2px solid var(--border);
    background:transparent; font-size:20px; cursor:pointer; transition:all 0.2s;
  }
  .pg-modal-wish2:hover { border-color:#ef4444; background:#fff1f2; }

  /* ── EMPTY STATE ── */
  .pg-empty { text-align:center; padding:80px 20px; }
  .pg-empty-icon { font-size:64px; margin-bottom:16px; display:block; }
  .pg-empty h3 { font-family:'Playfair Display',serif; font-size:22px; color:var(--brown); margin:0 0 8px; }
  .pg-empty p { color:#9a857a; font-size:14px; }

  /* ── LOADING ── */
  .pg-loading { display:grid; gap:24px; grid-template-columns:repeat(auto-fill,minmax(260px,1fr)); }
  .pg-skeleton {
    background:#fff; border-radius:20px; overflow:hidden; border:1px solid var(--border);
    animation:shimmer 1.4s ease infinite;
  }
  .pg-skel-img { height:195px; background:linear-gradient(90deg,#f5ede4 25%,#f0e4d7 50%,#f5ede4 75%); background-size:200%; animation:shimmerBg 1.4s ease infinite; }
  .pg-skel-body { padding:18px; }
  .pg-skel-line { height:12px; border-radius:6px; background:linear-gradient(90deg,#f5ede4 25%,#f0e4d7 50%,#f5ede4 75%); background-size:200%; animation:shimmerBg 1.4s ease infinite; margin-bottom:10px; }
  .pg-skel-line.w70 { width:70%; }
  .pg-skel-line.w50 { width:50%; }

  /* ── CART TOAST ── */
  .pg-toast {
    position:fixed; bottom:28px; right:28px; z-index:2000;
    background:var(--brown); color:#fff; border-radius:14px; padding:14px 20px;
    font-size:14px; font-weight:500; box-shadow:0 8px 32px rgba(0,0,0,0.25);
    display:flex; align-items:center; gap:10px;
    transform:translateY(80px); opacity:0; transition:all 0.35s cubic-bezier(0.34,1.56,0.64,1);
  }
  .pg-toast.show { transform:translateY(0); opacity:1; }
  .pg-toast-icon { font-size:20px; }

  /* ── ANIMATIONS ── */
  @keyframes fadeDown { from{opacity:0;transform:translateY(-16px)} to{opacity:1;transform:translateY(0)} }
  @keyframes fadeIn   { from{opacity:0} to{opacity:1} }
  @keyframes popIn    { from{opacity:0;transform:scale(0.9)} to{opacity:1;transform:scale(1)} }
  @keyframes cardIn   { from{opacity:0;transform:translateY(24px)} to{opacity:1;transform:translateY(0)} }
  @keyframes shimmerBg { 0%{background-position:200% 0} 100%{background-position:-200% 0} }

  /* ── RESPONSIVE ── */
  @media(max-width:600px) {
    .pg-hero { padding:60px 16px 80px; }
    .pg-stats { gap:24px; }
    .pg-grid { grid-template-columns:repeat(auto-fill,minmax(160px,1fr)); gap:14px; }
    .pg-card.list-view { grid-template-columns:1fr; }
    .pg-modal-features { grid-template-columns:1fr; }
    .pg-modal-body { padding:20px; }
  }
`;

// ─── Pet descriptions ─────────────────────────────────────────
const PET_INFO = {
  Affenpinscher: { cat: "Dogs", desc: "Playful, curious & fearless. Perfect apartment companion.", rating: 4.8, reviews: 124, badge: "hot" },
  Alaskan:       { cat: "Dogs", desc: "Energetic sled dog breed, loves outdoor adventures.", rating: 4.6, reviews: 89,  badge: "new" },
  "Alaskan Malamute": { cat: "Dogs", desc: "Powerful & loyal. Thrives in active families.", rating: 4.9, reviews: 203, badge: "hot" },
  "Airedale Terrier":  { cat: "Dogs", desc: "King of terriers. Intelligent, outgoing & confident.", rating: 4.7, reviews: 156, badge: null },
  "Dog Breeds":  { cat: "Dogs", desc: "Premium mixed-breed companions with great temperament.", rating: 4.5, reviews: 67,  badge: "sale" },
};

const getInfo = (name) =>
  PET_INFO[name] || { cat: "Pets", desc: "Beautiful, healthy & well-trained pet companion.", rating: 4.5 + Math.random() * 0.4, reviews: Math.floor(40 + Math.random() * 120), badge: null };

// ─── Component ────────────────────────────────────────────────
export default function PetGallery() {
  const [pets, setPets]           = useState([]);
  const [loading, setLoading]     = useState(true);
  const [search, setSearch]       = useState("");
  const [category, setCategory]   = useState("All");
  const [sort, setSort]           = useState("default");
  const [view, setView]           = useState("grid"); // grid | list
  const [wishlist, setWishlist]   = useState([]);
  const [cartAnim, setCartAnim]   = useState({});
  const [quickView, setQuickView] = useState(null);
  const [toast, setToast]         = useState({ show: false, name: "" });
  const navigate                  = useNavigate();

  useEffect(() => {
    fetch("http://localhost/Petshop/show.php")
      .then((r) => r.json())
      .then((data) => {
        // Attach fallback images & pet info
        const enriched = (data || []).map((p, i) => ({
          ...p,
          ...getInfo(p.pname),
          fallbackImg: FALLBACK_IMGS[i % FALLBACK_IMGS.length],
          price: parseInt(p.price) || 10000,
        }));
        setPets(enriched);
        setLoading(false);
      })
      .catch(() => {
        // Demo data if API fails
        setLoading(false);
      });
  }, []);

  // Filter + search + sort
  const filtered = pets
    .filter((p) => category === "All" || p.cat === category)
    .filter((p) => p.pname?.toLowerCase().includes(search.toLowerCase()))
    .sort((a, b) => {
      if (sort === "price-asc")  return a.price - b.price;
      if (sort === "price-desc") return b.price - a.price;
      if (sort === "rating")     return b.rating - a.rating;
      if (sort === "name")       return a.pname.localeCompare(b.pname);
      return 0;
    });

  const toggleWish = (id, e) => {
    e.stopPropagation();
    setWishlist((w) => w.includes(id) ? w.filter((x) => x !== id) : [...w, id]);
  };

  const addToCart = (pet, e) => {
    e?.stopPropagation();
    localStorage.setItem("item", pet.price);
    localStorage.setItem("id", localStorage.getItem("id") || 1);
    localStorage.setItem("pid", pet.id);
    setCartAnim((a) => ({ ...a, [pet.id]: true }));
    setTimeout(() => setCartAnim((a) => ({ ...a, [pet.id]: false })), 1400);
    setToast({ show: true, name: pet.pname });
    setTimeout(() => setToast({ show: false, name: "" }), 3000);
  };

  const buyNow = (pet) => {
    addToCart(pet);
    setTimeout(() => navigate("/checkout"), 300);
  };

  const imgSrc = (pet) => {
    // Use Unsplash fallback since localhost images won't load here
    return pet.fallbackImg || pet.image;
  };

  const stars = (rating) => {
    const full = Math.floor(rating);
    const half = rating % 1 >= 0.5;
    return "★".repeat(full) + (half ? "½" : "") + "☆".repeat(5 - full - (half ? 1 : 0));
  };

  // Category counts
  const catCount = (cat) =>
    cat === "All" ? pets.length : pets.filter((p) => p.cat === cat).length;

  return (
    <>
      <style>{css}</style>
      <div className="pg-root">
        <Nav />

        {/* ── HERO ── */}
        <div className="pg-hero">
          <div className="pg-hero-tag">🐾 Premium Pet Marketplace</div>
          <h1>Find Your Perfect<br /><em>Companion</em></h1>
          <p>Discover hand-picked, healthy, vaccinated pets from trusted breeders across India.</p>
          <div className="pg-stats">
            <div className="pg-stat">
              <span className="pg-stat-num">{pets.length || "50"}+</span>
              <span className="pg-stat-label">Pets Available</span>
            </div>
            <div className="pg-stat">
              <span className="pg-stat-num">100%</span>
              <span className="pg-stat-label">Health Verified</span>
            </div>
            <div className="pg-stat">
              <span className="pg-stat-num">4.9★</span>
              <span className="pg-stat-label">Avg Rating</span>
            </div>
            <div className="pg-stat">
              <span className="pg-stat-num">Free</span>
              <span className="pg-stat-label">Home Delivery</span>
            </div>
          </div>
        </div>

        {/* ── SEARCH + CONTROLS BAR ── */}
        <div className="pg-bar">
          <div className="pg-bar-inner">
            <div className="pg-search">
              <span className="pg-search-icon">🔍</span>
              <input
                placeholder="Search by breed, type..."
                value={search}
                onChange={(e) => setSearch(e.target.value)}
              />
            </div>
            <select className="pg-sort" value={sort} onChange={(e) => setSort(e.target.value)}>
              <option value="default">Sort: Featured</option>
              <option value="price-asc">Price: Low to High</option>
              <option value="price-desc">Price: High to Low</option>
              <option value="rating">Top Rated</option>
              <option value="name">A to Z</option>
            </select>
            <div className="pg-view-btns">
              <button className={`pg-view-btn ${view === "grid" ? "active" : ""}`} onClick={() => setView("grid")}>⊞</button>
              <button className={`pg-view-btn ${view === "list" ? "active" : ""}`} onClick={() => setView("list")}>☰</button>
            </div>
          </div>
        </div>

        {/* ── CATEGORY CHIPS ── */}
        <div className="pg-cats">
          {CATEGORIES.map((cat) => (
            <button
              key={cat}
              className={`pg-cat ${category === cat ? "active" : ""}`}
              onClick={() => setCategory(cat)}
            >
              {cat === "All" ? "🐾" : cat === "Dogs" ? "🐕" : cat === "Cats" ? "🐈" : cat === "Birds" ? "🦜" : cat === "Fish" ? "🐠" : cat === "Rabbits" ? "🐇" : "🦎"} {cat}
              <span className="pg-count">{catCount(cat)}</span>
            </button>
          ))}
        </div>

        {/* ── RESULTS INFO ── */}
        <div className="pg-info">
          <div className="pg-results">
            Showing <strong>{filtered.length}</strong> of <strong>{pets.length}</strong> pets
            {search && <> for "<strong>{search}</strong>"</>}
          </div>
          {(search || category !== "All") && (
            <button className="pg-clear" onClick={() => { setSearch(""); setCategory("All"); }}>
              Clear filters ✕
            </button>
          )}
        </div>

        {/* ── GRID ── */}
        <div className={`pg-grid ${view === "list" ? "list-view" : ""}`}>
          {loading
            ? Array(6).fill(0).map((_, i) => (
                <div className="pg-skeleton" key={i} style={{ animationDelay: i * 0.1 + "s" }}>
                  <div className="pg-skel-img" />
                  <div className="pg-skel-body">
                    <div className="pg-skel-line" />
                    <div className="pg-skel-line w70" />
                    <div className="pg-skel-line w50" />
                  </div>
                </div>
              ))
            : filtered.length === 0
            ? (
              <div className="pg-empty" style={{ gridColumn: "1/-1" }}>
                <span className="pg-empty-icon">🐾</span>
                <h3>No pets found</h3>
                <p>Try adjusting your search or filters</p>
              </div>
            )
            : filtered.map((pet, i) => (
              <div
                key={pet.id}
                className={`pg-card ${view === "list" ? "list-view" : ""}`}
                style={{ animationDelay: (i % 12) * 0.06 + "s" }}
                onClick={() => setQuickView(pet)}
              >
                {/* Image */}
                <div className="pg-img-wrap">
                  <img
                    src={imgSrc(pet)}
                    alt={pet.pname}
                    className="pg-img"
                    onError={(e) => { e.target.src = pet.fallbackImg; }}
                  />
                  <div className="pg-img-overlay" />
                  {pet.badge && <span className={`pg-badge ${pet.badge}`}>{pet.badge.toUpperCase()}</span>}
                  <button className={`pg-wish ${wishlist.includes(pet.id) ? "liked" : ""}`} onClick={(e) => toggleWish(pet.id, e)}>
                    {wishlist.includes(pet.id) ? "❤️" : "🤍"}
                  </button>
                  <button className="pg-quick" onClick={(e) => { e.stopPropagation(); setQuickView(pet); }}>
                    Quick View →
                  </button>
                </div>

                {/* Body */}
                <div className="pg-body">
                  <div className="pg-cat-tag">{pet.cat}</div>
                  <div className="pg-name">{pet.pname}</div>
                  {view === "list" && <div className="pg-desc">{pet.desc}</div>}
                  <div className="pg-rating">
                    <span className="pg-stars">{stars(pet.rating)}</span>
                    <span className="pg-rating-count">({pet.reviews} reviews)</span>
                  </div>
                  <div className="pg-price-row">
                    <div>
                      <span className="pg-price">
                        <em>₹</em>{pet.price.toLocaleString("en-IN")}
                      </span>
                    </div>
                    <button
                      className={`pg-add-btn ${cartAnim[pet.id] ? "added" : ""}`}
                      onClick={(e) => addToCart(pet, e)}
                    >
                      {cartAnim[pet.id] ? "✓ Added" : "+ Cart"}
                    </button>
                  </div>
                </div>
              </div>
            ))
          }
        </div>

        {/* ── QUICK VIEW MODAL ── */}
        {quickView && (
          <div className="pg-modal-bg" onClick={() => setQuickView(null)}>
            <div className="pg-modal" onClick={(e) => e.stopPropagation()}>
              <img src={imgSrc(quickView)} alt={quickView.pname} className="pg-modal-img"
                onError={(e) => { e.target.src = quickView.fallbackImg; }} />
              <button className="pg-modal-close" onClick={() => setQuickView(null)}>✕</button>
              <div className="pg-modal-body">
                <div className="pg-cat-tag" style={{ marginBottom: 6 }}>{quickView.cat}</div>
                <div className="pg-modal-name">{quickView.pname}</div>
                <div className="pg-rating" style={{ marginBottom: 12 }}>
                  <span className="pg-stars">{stars(quickView.rating)}</span>
                  <span className="pg-rating-count">({quickView.reviews} verified reviews)</span>
                </div>
                <div className="pg-modal-price">₹{quickView.price.toLocaleString("en-IN")}</div>
                <p style={{ color: "#7a6055", fontSize: 14, lineHeight: 1.7, marginBottom: 20 }}>
                  {quickView.desc} Comes with health certificate, vaccination record, and 7-day health guarantee.
                </p>
                <div className="pg-modal-features">
                  {[
                    { label: "Health Status", val: "✅ Vaccinated" },
                    { label: "Delivery",      val: "🚚 Free Pan India" },
                    { label: "Age",           val: "🐣 8–12 weeks" },
                    { label: "Guarantee",     val: "🛡️ 7-day health" },
                  ].map((f, i) => (
                    <div className="pg-modal-feat" key={i}>
                      <strong>{f.label}</strong>{f.val}
                    </div>
                  ))}
                </div>
                <div className="pg-modal-actions">
                  <button className="pg-modal-cart" onClick={() => { addToCart(quickView); setQuickView(null); }}>
                    🛒 Add to Cart — ₹{quickView.price.toLocaleString("en-IN")}
                  </button>
                  <button className="pg-modal-cart"
                    style={{ flex: "0 0 auto", background: "linear-gradient(135deg,#c8834a,#e0a06a)" }}
                    onClick={() => { setQuickView(null); buyNow(quickView); }}>
                    Buy Now
                  </button>
                  <button className={`pg-modal-wish2 ${wishlist.includes(quickView.id) ? "liked" : ""}`}
                    onClick={(e) => toggleWish(quickView.id, e)}>
                    {wishlist.includes(quickView.id) ? "❤️" : "🤍"}
                  </button>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* ── CART TOAST ── */}
        <div className={`pg-toast ${toast.show ? "show" : ""}`}>
          <span className="pg-toast-icon">🛒</span>
          <span><strong>{toast.name}</strong> added to cart!</span>
        </div>
      </div>
    </>
  );
}
